import{_ as o,o as a,c as t,ai as r}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{"summary":"Gateway dashboard (Control UI) access and auth","read_when":["Changing dashboard authentication or exposure modes"],"title":"Dashboard"},"headers":[],"relativePath":"web/dashboard.md","filePath":"web/dashboard.md","lastUpdated":1771906665000}'),n={name:"web/dashboard.md"};function s(d,e,c,i,l,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="dashboard-control-ui" tabindex="-1"><a class="header-anchor" href="#dashboard-control-ui">#</a> Dashboard (Control UI)</h1><p>The Gateway dashboard is the browser Control UI served at <code>/</code> by default (override with <code>gateway.controlUi.basePath</code>).</p><p>Quick open (local Gateway):</p><ul><li><a href="http://127.0.0.1:18789/" target="_blank" rel="noreferrer">http://127.0.0.1:18789/</a> (or <code>http://localhost:18789/</code>)</li></ul><p>Key references:</p><ul><li><a href="/docs/web/control-ui">Control UI</a> for usage and UI capabilities.</li><li><a href="/docs/gateway/tailscale">Tailscale</a> for Serve/Funnel automation.</li><li><a href="/docs/web/index">Web surfaces</a> for bind modes and security notes.</li></ul><p>Authentication is enforced at the WebSocket handshake via <code>connect.params.auth</code> (token or password). See <code>gateway.auth</code> in <a href="/docs/gateway/configuration">Gateway configuration</a>.</p><p>Security note: the Control UI is an <strong>admin surface</strong> (chat, config, exec approvals). Do not expose it publicly. The UI stores the token in <code>localStorage</code> after first load. Prefer localhost, Tailscale Serve, or an SSH tunnel.</p><h2 id="fast-path-recommended" tabindex="-1"><a class="header-anchor" href="#fast-path-recommended">#</a> Fast path (recommended)</h2><ul><li>After onboarding, the CLI auto-opens the dashboard and prints a clean (non-tokenized) link.</li><li>Re-open anytime: <code>opensoul dashboard</code> (copies link, opens browser if possible, shows SSH hint if headless).</li><li>If the UI prompts for auth, paste the token from <code>gateway.auth.token</code> (or <code>OPENSOUL_GATEWAY_TOKEN</code>) into Control UI settings.</li></ul><h2 id="token-basics-local-vs-remote" tabindex="-1"><a class="header-anchor" href="#token-basics-local-vs-remote">#</a> Token basics (local vs remote)</h2><ul><li><strong>Localhost</strong>: open <code>http://127.0.0.1:18789/</code>.</li><li><strong>Token source</strong>: <code>gateway.auth.token</code> (or <code>OPENSOUL_GATEWAY_TOKEN</code>); the UI stores a copy in localStorage after you connect.</li><li><strong>Not localhost</strong>: use Tailscale Serve (tokenless if <code>gateway.auth.allowTailscale: true</code>), tailnet bind with a token, or an SSH tunnel. See <a href="/docs/web/index">Web surfaces</a>.</li></ul><h2 id="if-you-see-unauthorized-1008" tabindex="-1"><a class="header-anchor" href="#if-you-see-unauthorized-1008">#</a> If you see “unauthorized” / 1008</h2><ul><li>Ensure the gateway is reachable (local: <code>opensoul status</code>; remote: SSH tunnel <code>ssh -N -L 18789:127.0.0.1:18789 user@host</code> then open <code>http://127.0.0.1:18789/</code>).</li><li>Retrieve the token from the gateway host: <code>opensoul config get gateway.auth.token</code> (or generate one: <code>opensoul doctor --generate-gateway-token</code>).</li><li>In the dashboard settings, paste the token into the auth field, then connect.</li></ul>',14)])])}const f=o(n,[["render",s]]);export{p as __pageData,f as default};
